mapper.sql:
SELECT
A.ID,
A.RATE_ITEM_CODE,
A.RATE_ITEM_NAME,
A.SERVICE_CONTENT_ID,
A.SERVICE_CONTENT_NAME,
A.PROCESS_CODE,
A.PROCESS_NAME,
A.CARGO_CODE,
A.CARGO_NAME,
A.INTE_FORE,
A.RATE,
A.TAX_RATE,
A.WORK_TYPE,
A.MEASUREMENT_UNIT_CODE1,
B.DICT_LABEL  AS MEASUREMENT_UNIT_NAME1,
A.MEASUREMENT_UNIT_CODE2,
C.DICT_LABEL  AS MEASUREMENT_UNIT_NAME2,
A.STATUS,
M2.NM AS STATUS_LABEL,
A.START_DATE,
A.END_DATE,
A.FREE_STORAGE_DAYS,
A.REMARK,
A.EXAMINE_BY,
A.EXAMINE_BY_NAME,
A.EXAMINE_TIME,
A.CREATE_BY,
A.CREATE_BY_NAME,
A.CREATE_TIME,
A.UPDATE_BY,
A.UPDATE_BY_NAME,
A.UPDATE_TIME,
A.DATA_SOURCE
FROM
    T_BUS_RATE A
left join M_CONSTANTS M2 ON A.STATUS=M2.CD and M2.TYPE_CD='RATE_STATUS'
left join M_DICT_DATA B on B.DICT_TYPE = 'UNIT' and B.DICT_VALUE=A.MEASUREMENT_UNIT_CODE1
left join M_DICT_DATA C on C.DICT_TYPE = 'UNIT' and C.DICT_VALUE=A.MEASUREMENT_UNIT_CODE2


        and A.DATA_SOURCE = #{dataSource}


        and A.RATE_ITEM_CODE = #{rateItemCode}



        and A.RATE_ITEM_NAME like #{rateItemNameLike}


        and A.SERVICE_CONTENT_ID = #{serviceContentId}


        and A.SERVICE_CONTENT_NAME = #{serviceContentName}


        and A.PROCESS_CODE = #{processCode}


        and A.PROCESS_NAME = #{processName}


        and A.CARGO_CODE = #{cargoCode}


        and A.CARGO_NAME = #{cargoName}


        and A.INTE_FORE = #{inteFore}


        and A.RATE = #{rate}


        and A.TAX_RATE = #{taxRate}


        and A.MEASUREMENT_UNIT_CODE1 = #{measurementUnitCode1}


        and A.MEASUREMENT_UNIT_CODE2 = #{measurementUnitCode2}


        and A.STATUS = #{status}


        and A.START_DATE = #{startDate}


        and A.END_DATE = #{endDate}


        and A.REMARK = #{remark}


order by A.CREATE_TIME desc

mapper.select:
SELECT A1.CARGO_CODE "cargoCode", A1.CARGO_NAME "cargoName", A3.CARGO_CATEGORY_CODE "cargoCategoryCode", A3.CARGO_CATEGORY_NAME "cargoCategoryName", A3.CARGO_TYPE_CODE "cargoTypeCode", A3.CARGO_TYPE_NAME "cargoTypeName", A1.START_DATE "startDate", A1.END_DATE "endDate", A1.STATUS, A2.SIGN FROM T_BUS_RATE A1 LEFT JOIN M_CARGO A2 on A1.CARGO_CODE = a2.CARGO_CODE LEFT JOIN M_CARGO_CATEGORY A3 on a2.CARGO_CATEGORY_CODE = a3.CARGO_CATEGORY_CODE
and A1.DATA_SOURCE = #{dataSource}
and A1.CARGO_CODE = #{cargoCode}
and A1.CARGO_NAME LIKE #{cargoNm}
and A1.STATUS = #{status}
GROUP BY A1.CARGO_CODE, A1.CARGO_NAME, A3.CARGO_CATEGORY_CODE, A3.CARGO_CATEGORY_NAME, A3.CARGO_TYPE_CODE, A3.CARGO_TYPE_NAME, A1.START_DATE, A1.END_DATE, A1.STATUS, A2.SIGN

mapper.insert:
INSERT INTO T_BUS_RATE_LOG( ID, RATE_ID, RATE_ITEM_CODE, RATE_ITEM_NAME, SERVICE_CONTENT_ID, SERVICE_CONTENT_NAME, CARGO_CODE, CARGO_NAME, INTE_FORE, RATE, TAX_RATE, MEASUREMENT_UNIT_CODE1, MEASUREMENT_UNIT_CODE2, START_DATE, END_DATE, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, FLAG ) (
select #{item.id, jdbcType=BIGINT}, #{item.rateId, jdbcType=BIGINT}, #{item.rateItemCode,jdbcType=VARCHAR}, #{item.rateItemName, jdbcType=VARCHAR}, #{item.serviceContentId, jdbcType=BIGINT}, #{item.serviceContentName, jdbcType=VARCHAR}, #{item.cargoCode, jdbcType=VARCHAR}, #{item.cargoName, jdbcType=VARCHAR}, #{item.inteFore, jdbcType=VARCHAR}, #{item.rate,jdbcType=DECIMAL}, #{item.taxRate, jdbcType=DECIMAL}, #{item.measurementUnitCode1, jdbcType=VARCHAR}, #{item.measurementUnitCode2, jdbcType=VARCHAR}, #{item.startDate, jdbcType=DATE}, #{item.endDate, jdbcType=DATE}, #{item.remark, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now}, #{item.flag,jdbcType=VARCHAR} from dual
)

mapper.select:
SELECT A.ID, A.RATE_ITEM_CODE, A.RATE_ITEM_NAME, A.SERVICE_CONTENT_ID, A.SERVICE_CONTENT_NAME, A.PROCESS_CODE, A.PROCESS_NAME, A.CARGO_CODE, A.CARGO_NAME, A.INTE_FORE, A.RATE, A.TAX_RATE, A.WORK_TYPE, A.MEASUREMENT_UNIT_CODE1, B.DICT_LABEL AS MEASUREMENT_UNIT_NAME1, A.MEASUREMENT_UNIT_CODE2, C.DICT_LABEL AS MEASUREMENT_UNIT_NAME2, A.STATUS, M2.NM AS STATUS_LABEL, A.START_DATE, A.END_DATE, A.FREE_STORAGE_DAYS, A.REMARK, A.EXAMINE_BY, A.EXAMINE_BY_NAME, A.EXAMINE_TIME, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, A.DATA_SOURCE FROM T_BUS_RATE A left join M_CONSTANTS M2 ON A.STATUS=M2.CD and M2.TYPE_CD='RATE_STATUS' left join M_DICT_DATA B on B.DICT_TYPE = 'UNIT' and B.DICT_VALUE=A.MEASUREMENT_UNIT_CODE1 left join M_DICT_DATA C on C.DICT_TYPE = 'UNIT' and C.DICT_VALUE=A.MEASUREMENT_UNIT_CODE2
and A.DATA_SOURCE = #{dataSource}
and A.RATE_ITEM_CODE = #{rateItemCode}
and A.RATE_ITEM_NAME = #{rateItemName}
and A.SERVICE_CONTENT_ID = #{serviceContentId}
and A.SERVICE_CONTENT_NAME = #{serviceContentName}
and A.PROCESS_CODE = #{processCode}
and A.PROCESS_NAME = #{processName}
and A.CARGO_CODE = #{cargoCode}
and A.CARGO_NAME = #{cargoName}
and A.INTE_FORE = #{inteFore}
and A.RATE = #{rate}
and A.TAX_RATE = #{taxRate}
and A.MEASUREMENT_UNIT_CODE1 = #{measurementUnitCode1}
and A.MEASUREMENT_UNIT_CODE2 = #{measurementUnitCode2}
and A.STATUS = #{status}
AND TO_DATE(#{currTime, jdbcType=VARCHAR}, 'yyyy-MM-dd') >= A.START_DATE AND TO_DATE(#{currTime, jdbcType=VARCHAR}, 'yyyy-MM-dd') <= A.END_DATE
order by A.CREATE_TIME desc
